INSERT INTO "scenarios" ("id","title","data","created_at","updated_at") VALUES('fdrjgs46','FIRST COMMIT','{"tipoEscenario":"VS","acto":"Acto 1","numeroEscenario":1,"numeroTurnos":0,"numeroJugadores":2,"numeroBots":2,"ambientacion":"Inicias sesión. El zumbido de los ventiladores de tu terminal es lo único que rompe el silencio en tu cubículo. Es el Acto 1, el primer bloque de una cadena de ejecución que, si tienes el talento necesario, te llevará hasta la Gran Final. Pero seamos sinceros: hoy la red te mira con escepticismo. ¿Eres un arquitecto de código o solo otro script kiddie destinado a ser borrado?\n\nHas invertido tus últimos 120◈ en optimizar cada función. Tus Bots no tienen el brillo cromado de las unidades de élite, pero su código es crudo, eficiente y tuyo. Al otro lado de la arena, tu rival ya ha ejecutado su secuencia INIT(). Sus sensores parpadean con una frialdad corporativa que no perdona errores.\n\nEn las Firmware Wars no hay calentamiento. Si aspiras a los grandes premios, primero debes demostrar que puedes sobrevivir a este primer \"apretón de manos\" letal. El buffer está cargado, los protocolos están listos y la latencia es cero. Es hora de compilar tu destino.","objetivo":"El primer Programador que destruya una unidad del equipo rival completa el objetivo y gana el escenario.\nSi ambos jugadores pierden un Bot en el mismo turno, el escenario termina en empate.","condicionDerrota":"","amenazaIds":[],"linkedFunctions":["2s9t5d3m"],"amenazaCounts":{"x99yfe5t":4},"amenazaTurnos":{"x99yfe5t":[null,1,2]},"despliegueMode":"map","despliegueDots":{"1":"green","2":"yellow","3":"blue"},"hexMap":{"hexTypes":[{"id":"normal","name":"Normal","color":"#ffffff","borderColor":"#1a1a1a","properties":{},"builtIn":true},{"id":"obstacle","name":"Obstaculo","color":"#1a1a1a","borderColor":"#333333","properties":{"traversable":"false"},"builtIn":true},{"id":"uwh48xb6","name":"Hielo","color":"#4281ff","border_color":"#24478c","properties":"Sed ut perspiciatis unde omni