INSERT INTO "scenarios" ("id","title","data","created_at","updated_at") VALUES('bpwtrqpm','DATA HEIST','{"tipoEscenario":"VS","acto":"Acto 1","numeroEscenario":2,"numeroTurnos":0,"numeroJugadores":2,"numeroBots":2,"ambientacion":"Has sobrevivido al primer commit, pero la arquitectura de las Firmware Wars no perdona. Has demostrado que tus Bots pueden mantener el control bajo presión. Pero la Red es un organismo hambriento y ahora te exige un precio más alto para seguir escalando. Ahora, te encuentras en una Bóveda de Datos de Grado Militar, un nivel donde la información no fluye libremente, sino que está fragmentada. \n\nDebes conseguir la **Llave Maestra de Cifrado** antes de que sea purgada. Sin esta llave, tu ruta hacia la Gran Final quedará bloqueada por un Firewall difícil de superar. No basta con localizar la llave; debes cargarla en la memoria volátil de tus Bots y transportarlos físicamente hasta el Terminal de Uplink central.\n\nEste nodo es la única salida de banda ancha capaz de extraer los paquetes antes de que el sector entre en cuarentena total. Si tu unidad cae, los datos quedarán expuestos en el suelo del mapa, listos para que tu rival los \"recicle\" y se lleve el mérito de tu infiltración. Muévete rápido, protege tus registros y no dejes que el enemigo intercepte lo que tanto te ha costado encontrar. Ejecuta la extracción.","objetivo":"**Recoge la Llave Maestra de Cifrado (B1) del centro del tablero y llévala hasta tu Hex de salida.**\nEl Hex de salida de cada jugador está en territorio enemigo — en el extremo opuesto del tablero respecto a su despliegue inicial. El escenario termina en el momento en que un Bot portador llega a su Hex de salida con la bandera.","condicionDerrota":"","amenazaIds":[],"linkedFunctions":[],"amenazaCounts":{"x99yfe5t":1},"amenazaTurnos":{},"despliegueMode":"map","despliegueDots":{"1":"green","2":"blue"},"hexMap":{"hexTypes":[{"id":"normal","name":"Normal","color":"#ffffff","borderColor":"#1a1a1a","properties":{},"builtI