PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE lists (
  id TEXT PRIMARY KEY,
  programmer TEXT NOT NULL,
  data TEXT NOT NULL,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE scenarios (id TEXT PRIMARY KEY, title TEXT NOT NULL, data TEXT NOT NULL, created_at DATETIME, updated_at DATETIME);
CREATE TABLE threats (id TEXT PRIMARY KEY, name TEXT NOT NULL, description TEXT NOT NULL DEFAULT '', data TEXT NOT NULL DEFAULT '{}', created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE hex_types (id TEXT PRIMARY KEY, name TEXT NOT NULL, color TEXT NOT NULL, border_color TEXT NOT NULL, properties TEXT NOT NULL DEFAULT '{}', created_at DATETIME DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE functions (
  id TEXT PRIMARY KEY,
  func_name TEXT NOT NULL,
  version TEXT NOT NULL DEFAULT '',
  range TEXT NOT NULL DEFAULT '',
  damage TEXT NOT NULL DEFAULT '',
  energy TEXT NOT NULL DEFAULT '',
  cost TEXT NOT NULL DEFAULT '',
  effects TEXT NOT NULL DEFAULT ''
, func_type TEXT DEFAULT 'attack');
